{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラは本日付で正式キックオフし、正式発足とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例は毎週水曜日10:00開始の1時間枠で開催し、各部署から少なくとも1名が参加する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "本番リリース目標は2026-10-15とする。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "移行方式は拠点を分けて順番に切り替える段階移行を採用する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "本番切替は土曜の深夜帯に実施する。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "データ移行は第1フェーズでマスタ系を先行し、トランザクション系は後フェーズに回して旧システムを参照用に残す。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "認証とマスタ配信の基盤はサクラ商事さんとの共同利用で進める。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "障害の一次受け窓口はQAチームが担う。",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "新システムのユーザー権限は既存のロール定義を流用し、新規設計はしない。",
      "decided_by": "桐生 遥"
    }
  ],
